using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;
using YourNamespace.Models; // Adjust namespace according to your project structure

public class ReviewsController : Controller
{
    private YourDbContext db = new YourDbContext(); // Your Entity Framework context

    public ActionResult Index(int productId)
    {
        var reviews = db.Reviews.Where(r => r.ProductId == productId).ToList();
        return View(reviews);
    }

    [HttpPost]
    [ValidateAntiForgeryToken]
    public ActionResult SubmitReview(int productId, string reviewText)
    {
        if (ModelState.IsValid)
        {
            var review = new Review
            {
                ProductId = productId,
                ReviewText = reviewText,
                SubmittedAt = DateTime.Now
            };

            db.Reviews.Add(review);
            db.SaveChanges();
            return RedirectToAction("Index", new { productId });
        }

        return View();
    }
}

@model IEnumerable<YourNamespace.Models.Review> // Update namespace according to your project structure

@{
    ViewBag.Title = "Product Reviews";
}

<h2>Product Reviews</h2>

<form action="@Url.Action("SubmitReview", "Reviews")" method="post">
    @Html.AntiForgeryToken()
    <input type="hidden" name="productId" value="@(ViewBag.ProductId)" />
    <textarea name="reviewText" required></textarea>
    <button type="submit">Submit Review</button>
</form>

<div>
    @foreach (var review in Model)
    {
        <div>
            @Html.Raw(review.ReviewText) <br />
            <small>Submitted on: @review.SubmittedAt.ToString("g")</small>
        </div>
    }
</div>